//     label: "Mein Logo",
//     cat: "SVG",
//     fc: {
//       k: "svg",
//       markup: `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100">
//                  <circle cx="50" cy="50" r="40" fill="none" stroke="currentColor" stroke-width="4"/>
